    let key_copy = key.clone();          // Unnecessary clone
    let nonce_copy = nonce.clone();      // Unnecessary clone
    let ciphertext_copy = ciphertext.clone(); // Unnecessary clone

    // ... use the copies
    Ok(result)
}

// AFTER:
fn decrypt_slice(key: &[u8; 32], nonce: &[u8; 12], ciphertext: &[u8]) -> Result<Vec<u8>, CryptoError> {
    // Use references directly
    // ... use key, nonce, ciphertext
    Ok(result)
}
```

2. When mutation is needed, use mutable references:
```rust
// BEFORE:
fn process_buffer(mut buffer: Vec<u8>) -> Vec<u8> {
    let mutated = buffer.clone();
    // mutate cloned buffer...
    mutated
}

// AFTER:
fn process_buffer(buffer: &mut Vec<u8>) -> &mut Vec<u8> {
    // mutate buffer directly
    buffer
}
```

3. For large data processing, use streaming/chunked approaches:
```rust
// BEFORE:
fn decrypt_large_file(key: &[u8; 32], nonce: [u8; 12], ciphertext: Vec<u8>) -> Vec<u8> {
    let decrypted = decrypt_slice(&key, &nonce, &ciphertext)?;
    decrypted
}

// AFTER:
fn decrypt_large_file<R, W>(\n    key: &[u8; 32],\n    nonce: &[u8; 12],\n    reader: &mut R,\n    writer: &mut W\n) -> Result<(), CryptoError> \nwhere\n    R: Read,\n    W: Write,
{
    let mut decryptor = Decryptor::new(key, nonce)?;
    \n    // Process in chunks to avoid loading entire file into memory
    let mut buffer = [0u8; 8192];
    loop {
        let bytes_read = reader.read(&mut buffer)?;
        if bytes_read == 0 {
            break;  // EOF
        }

        let decrypted = decryptor.decrypt(&buffer[..bytes_read])?;
        writer.write_all(&decrypted)?;
    }

    Ok(())
}
```

